input.content:
/// <reference path="../pb_data/types.d.ts" />

cronAdd("archive_old_messages", "0 0 * * *", () => {
    const threshold = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

    const pad = (n) => String(n).padStart(2, "0");
    const thresholdStr =
        threshold.getFullYear() +
        "-" +
        pad(threshold.getMonth() + 1) +
        "-" +
        pad(threshold.getDate()) +
        " " +
        pad(threshold.getHours()) +
        ":" +
        pad(threshold.getMinutes()) +
        ":" +
        pad(threshold.getSeconds()) +
        ".000Z";

    const filter = `created < "${thresholdStr}" && archived = false`;

    const records = $app.dao().findRecordsByFilter("messages", filter);

    for (const record of records) {
        record.set("archived", true);
        $app.dao().saveRecord(record);
    }

    console.log(`[archive_old_messages] Archived ${records.length} message(s) older than ${thresholdStr}`);
});

